    tree = {}
    for j in range(437900, 437900 + 30):
        tree[f"node_{j}"] = {f"child_{k}": k * j for k in range(10)}
    expect(len(tree)).to_equal(30)
    flat = [v for children in tree.values() for v in children.values()]
    expect(len(flat)).to_equal(300)


